//! Loads the capture-derived static game definitions (see
//! `blades_lib::static_data`) from JSON files in the `--static-data` directory at
//! startup. Each file is independently optional: a missing or invalid file logs a
//! warning and leaves that part of [`StaticData`] empty rather than failing the
//! server (the corresponding endpoint then degrades to an empty/default response).
//!
//! The files are generated by `blades-capture/scripts/extract-static-data.py` and
//! committed under `deploy/static/`.

use std::{collections::HashMap, fs::File, io::BufReader, path::Path};

use blades_lib::static_data::{Announcement, GiftDef, StaticData};
use log::warn;
use serde::de::DeserializeOwned;

/// Read a JSON file into `T`, falling back to `T::default()` (with a warning) if the
/// file is missing or invalid.
fn read_json<T: DeserializeOwned + Default>(path: &Path) -> T {
    match File::open(path) {
        Ok(f) => serde_json::from_reader(BufReader::new(f)).unwrap_or_else(|e| {
            warn!("[static] invalid {path:?}: {e}; using default");
            T::default()
        }),
        Err(e) => {
            warn!("[static] no {path:?}: {e}; using default");
            T::default()
        }
    }
}

pub fn load(dir: &Path) -> StaticData {
    let gifts: Vec<GiftDef> = read_json(&dir.join("gifts.json"));
    let announcements: Vec<Announcement> = read_json(&dir.join("announcements.json"));

    StaticData {
        gifts: gifts.into_iter().map(|g| (g.global_gift_id, g)).collect::<HashMap<_, _>>(),
        announcements,
    }
}
